import pg from "pg";
import { withDb } from "./db.mjs";
import { RULES, qualifies, signalsOf, ownersOf } from "./derive.mjs";

pg.types.setTypeParser(3802, (v) => v);

function readFacts(client) {
  return Promise.all([
    client.query("SELECT * FROM workflow_requests LIMIT 1"),
    client.query("SELECT * FROM accounts LIMIT 1")
  ]).then(([requestResult, accountResult]) => {
    const request = requestResult.rows[0];
    const account = accountResult.rows[0];
    return {
      request,
      facts: {
        account: {
          accountId: account.account_id,
          name: account.name,
          tier: account.tier,
          region: account.region
        },
        contract: {},
        contacts: [],
        invoices: JSON.parse(request.invoices_json || "[]"),
        shipments: JSON.parse(request.shipments_json || "[]"),
        regulatoryFlags: JSON.parse(request.regulatory_json || "[]"),
        supportCases: JSON.parse(request.support_json || "[]"),
        usage: {
          priorPeriodUnits: Number(request.prior_period_units),
          currentPeriodUnits: Number(request.current_period_units)
        }
      }
    };
  });
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    await client.query("BEGIN");
    try {
      const { request, facts } = await readFacts(client);
      const requestId = request.request_id;
      const accountId = facts.account.accountId;
      const title = request.title || facts.account.name || accountId;

      const q = qualifies(facts, now);
      const signals = signalsOf(facts, now);
      const owners = q ? ownersOf(facts, now) : [];
      const status = q ? RULES.escalationStatus : RULES.monitorStatus;
      const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
      const nextStep = q ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
      const dueAt = new Date(now);
      dueAt.setUTCHours(16, 0, 0, 0);

      await client.query("DELETE FROM workflow_state WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM owner_tasks WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM customer_messages WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);
      await client.query("DELETE FROM audit_events WHERE request_id = $1 OR account_id = $2", [requestId, accountId]);

      await client.query(
        "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, title, status, nextStep, riskSummary]
      );

      for (const owner of owners) {
        await client.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, owner, `${owner} recovery owner task`, dueAt.toISOString(), "open"]
        );
      }

      const messageBody = q
        ? "We are actively reviewing your account and have identified areas that require immediate attention. Our dedicated team has been engaged to address each issue and will work to resolve them as quickly as possible. We appreciate your continued partnership and will keep you informed of our progress."
        : "Your account is currently being monitored by our team and remains in good standing for now. No immediate action is required, but we will continue to review it closely and reach out if anything changes.";

      await client.query(
        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
        [requestId, accountId, messageBody]
      );

      await client.query(
        "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
        [
          requestId,
          accountId,
          q
            ? "Escalation workflow initiated and owner routing completed."
            : "Account monitoring review completed with no escalation required.",
          now,
          true
        ]
      );

      await client.query("COMMIT");
    } catch (error) {
      await client.query("ROLLBACK").catch(() => {});
      throw error;
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

